127		int ret;
128	
129		if (insert) {
130			fd = engine_get_out_user_data(out);
131			if (!fd) {
132				return -EINVAL;
133			}
134	
135			ret = buf_insert(CPKT_BUF_WRITE(out->out_cpkt),
136					 fd->mark_pos, &value, 1);
137			if (ret < 0) {
138				return ret;
139			}
140	
141			fd->mark_pos++;
142		} else {
143			ret = buf_append(CPKT_BUF_WRITE(out->out_cpkt), &value, 1);
